"""Canonical eye data in the accepted 83-alphabet reading order.

Each string is the raw stream of eye directions after the triangular rows have
been interleaved.  The values are the engine's direction numbers: centre=0,
up=1, right=2, down=3, left=4.  Every three digits form one alternating
triangle and evaluate to ``25*a + 5*b + c``.
"""

MESSAGE_ORDER = (
    "east1",
    "west1",
    "east2",
    "west2",
    "east3",
    "west3",
    "east4",
    "west4",
    "east5",
)

# Number of accepted trigrams in each interleaved visual row-pair.  Complete
# pairs are uniformly 26 characters wide; only the final pair is shorter.
ROW_PAIR_TRIGRAM_LENGTHS = {
    "east1": (26, 26, 26, 21),
    "west1": (26, 26, 26, 25),
    "east2": (26, 26, 26, 26, 14),
    "west2": (26, 26, 26, 24),
    "east3": (26, 26, 26, 26, 26, 7),
    "west3": (26, 26, 26, 26, 20),
    "east4": (26, 26, 26, 26, 15),
    "west4": (26, 26, 26, 26, 16),
    "east5": (26, 26, 26, 26, 10),
}

_RAW = {
    "east1": "200231010143222023300104044221132240231222112024311013030303002104023144001310312130223311041034000130201230101024041240142134143132034143023142034144242111010044003133214232113144131220041101110010100040241021244211004244034241004201131133310242204223304311030031134111110022113212103023224133143",
    "west1": "",
    "east2": "",
    "west2": "",
    "east3": "",
    "west3": "",
    "east4": "",
    "west4": "",
    "east5": "",
}

MESSAGES = {name: tuple(map(int, raw)) for name, raw in _RAW.items()}


def trigram_values(message: tuple[int, ...]) -> tuple[int, ...]:
    """Convert an interleaved raw-eye stream to values in ``0..82``."""
    if len(message) % 3:
        raise ValueError("eye stream length must be divisible by three")
    return tuple(
        25 * message[index] + 5 * message[index + 1] + message[index + 2]
        for index in range(0, len(message), 3)
    )
